PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE client_collaborateurs (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            client_id INTEGER NOT NULL,
            subdomain TEXT NOT NULL,
            gateway_token TEXT NOT NULL,
            gateway_port INTEGER DEFAULT 18789,
            display_name TEXT DEFAULT '',
            display_role TEXT DEFAULT '',
            is_default INTEGER DEFAULT 0, agent_id TEXT DEFAULT '', session_key TEXT DEFAULT '', workspace_path TEXT DEFAULT '', voice_config TEXT DEFAULT NULL,
            FOREIGN KEY (client_id) REFERENCES clients(id),
            UNIQUE(client_id, subdomain)
        );
